Code
filtered_for_select = (() =&gt; {
  const q = (search_query || "").trim().toLowerCase()
  if (q === "") return etf_search_index
  // Split on whitespace — every token must match
  const tokens = q.split(/\s+/).filter(t =&gt; t.length &gt; 0)
  return etf_search_index.filter(d =&gt;
    tokens.every(t =&gt; d.haystack.includes(t))
  )
})

