function bestBy(metric, higher = true) {
  const valid = summary_df.filter(d =&gt;
    d[metric] != null && !isNaN(d[metric]) && isFinite(d[metric])
  )
  if (!valid.length) return null
  return valid.reduce((a, b) =&gt;
    higher ? (b[metric] &gt; a[metric] ? b : a) : (b[metric] &lt; a[metric] ? b : a)
  )
}

